My simple approach for the version management, O(1) write and read, please tell me what you think:

```
public class VersionCompatibilityManagement {
    Map<Integer, Integer> backwardsCompatibility = new HashMap<>();
    Integer latestList = 0;

    public void addNewVersion(int ver, boolean isCompatibleWithPrev) {
        if (!isCompatibleWithPrev) {
            latestList++;
        }

        backwardsCompatibility.put(ver, latestList);
    }

    public boolean isCompatible(int srcVer, int targetVer) {
        if (!backwardsCompatibility.containsKey(srcVer)) throw new RuntimeException("Unknown version " + srcVer);
        if (!backwardsCompatibility.containsKey(targetVer)) throw new RuntimeException("Unknown version " + targetVer);

        return backwardsCompatibility.get(srcVer).equals(backwardsCompatibility.get(targetVer));
    }
}
```

Is this simple dfs approach acceptable for Question 3?

```
public class VersionControl {

    Map<Integer, Set<Integer>> map = new HashMap<>();

    private void addNewVersion(int version, boolean isCompatible){
        map.putIfAbsent(version, new HashSet<>());
        if(isCompatible){
            map.get(version).add(version-1);
        }
    }

    private boolean dfs(int version1, int target){
        if(map.get(version1).contains(target)) return true;

        for(int v : map.get(version1)){
            if(dfs(v, target)) return true;
        }

        return false;
    }

    private boolean isCompatible(int version1, int version2){
        if(version1 == version2) return true;
        else if(version1 < version2) return isCompatible(version2, version1);

        return dfs(version1, version2);
    }

    public static void main(String[] args){
        VersionControl versions = new VersionControl();
        versions.addNewVersion(1, false);
        versions.addNewVersion(2, true);
        versions.addNewVersion(3, true);
        versions.addNewVersion(4, false);
        versions.addNewVersion(5, true);
        versions.addNewVersion(6, true);
        System.out.println(versions.map);
        System.out.println(versions.isCompatible(1, 3));
        System.out.println(versions.isCompatible(3, 5));
        System.out.println(versions.isCompatible(4, 2)); // downgrade
        System.out.println(versions.isCompatible(3, 3)); // upgrade to itself, always compatible
    }
}

```
